// TestExternalToolRegistry_ToolCollision tests internal tool precedence
func TestExternalToolRegistry_ToolCollision(t *testing.T) {
	// This test verifies that when an external tool tries to register with the same name
	// as an internal tool, the registration should log a warning but the internal tool
	// should take precedence in execution and listing.

	registry := agentictools.NewExecutorRegistry()

	// Register internal tool
	internalExecutor := &mockToolExecutor{
		name: "graph_query",
		listToolsFunc: func() []agentic.ToolDefinition {
			return []agentic.ToolDefinition{
				{
					Name:        "graph_query",
					Description: "Internal graph query",
					Parameters: map[string]any{
						"type": "object",
					},
				},
			}
		},
	}
	err := registry.RegisterTool("graph_query", internalExecutor)
	if err != nil {
		t.Fatalf("RegisterTool() for internal tool failed: %v", err)
	}

	// Create external registry
	externalRegistry := agentictools.NewExternalToolRegistry()

	// Register external tool with same name
	externalReg := agentictools.ExternalToolRegistration{
		Name:        "graph_query",
		Description: "External graph query",
		Provider:    "external-provider",
		Parameters: map[string]interface{}{
			"type": "object",
		},
		Timestamp: time.Now(),
	}

	// External registration should succeed (it's in separate namespace)
	err = externalRegistry.RegisterExternalTool(externalReg)
	if err != nil {
		t.Fatalf("RegisterExternalTool() should succeed even with name collision, got error: %v", err)
	}

	// When combined, internal tool should take precedence
	// This will be tested in the component integration, but we verify
	// that both registries can coexist with same tool names
	internalTools := registry.ListTools()
	externalTools := externalRegistry.ListExternalTools()

	foundInternal := false
	foundExternal := false

	for _, tool := range internalTools {
		if tool.Name == "graph_query" {
			foundInternal = true
			if tool.Description != "Internal graph query" {
				t.Error("Internal tool should maintain its description")
			}
		}
	}

	for _, tool := range externalTools {
		if tool.Name == "graph_query" {
			foundExternal = true
			if tool.Description != "External graph query" {
				t.Error("External tool should maintain its description")
			}
		}
	}

	if !foundInternal {
		t.Error("Internal tool should be present in internal registry")
	}
	if !foundExternal {
		t.Error("External tool should be present in external registry")
	}
}

// TestExternalToolRegistry_ConcurrentRegistration tests concurrent tool registration
func TestExternalToolRegistry_ConcurrentRegistration(t *testing.T) {
	registry := agentictools.NewExternalToolRegistry()

	// Register tools concurrently
	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(n int) {
			defer wg.Done()
			reg := agentictools.ExternalToolRegistration{
				Name:        "tool_" + string(rune('0'+n)),
				Description: "Concurrent tool",
				Provider:    "concurrent-provider",
				Parameters: map[string]interface{}{
					"type": "object",
				},
				Timestamp: time.Now(),
			}
			_ = registry.RegisterExternalTool(reg)
		}(i)
	}

	// Wait for all registrations
	wg.Wait()

	// All tools should be registered (race detector will catch issues)
	tools := registry.ListExternalTools()
	if len(tools) == 0 {
		t.Error("ListExternalTools() should return registered tools")
	}
}

