// TestExternalToolRegistry_MultipleProvidersSameTool tests multiple providers registering same tool name
func TestExternalToolRegistry_MultipleProvidersSameTool(t *testing.T) {
	registry := agentictools.NewExternalToolRegistry()

	// Register same tool name from different providers
	providers := []string{"provider-1", "provider-2", "provider-3"}
	for _, provider := range providers {
		reg := agentictools.ExternalToolRegistration{
			Name:        "file_read",
			Description: "Read a file from " + provider,
			Provider:    provider,
			Parameters: map[string]interface{}{
				"type": "object",
			},
			Timestamp: time.Now(),
		}
		err := registry.RegisterExternalTool(reg)
		if err != nil {
			t.Fatalf("RegisterExternalTool() from %s failed: %v", provider, err)
		}
	}

	// All three should be registered
	tools := registry.ListExternalTools()
	count := 0
	for _, tool := range tools {
		if tool.Name == "file_read" {
			count++
		}
	}

	if count != len(providers) {
		t.Errorf("Expected %d tools named 'file_read', got %d", len(providers), count)
	}

	// Unregister from one provider
	unreg := agentictools.ToolUnregister{
		Name:     "file_read",
		Provider: "provider-1",
	}
	err := registry.UnregisterTool(unreg)
	if err != nil {
		t.Fatalf("UnregisterTool() failed: %v", err)
	}

	// Should still have 2 remaining
	tools = registry.ListExternalTools()
	count = 0
	for _, tool := range tools {
		if tool.Name == "file_read" {
			count++
			if tool.Provider == "provider-1" {
				t.Error("Tool from provider-1 should be unregistered")
			}
		}
	}

	if count != 2 {
		t.Errorf("Expected 2 tools named 'file_read' after unregister, got %d", count)
	}
}

// TestExternalToolRegistry_HeartbeatUpdatesTimestamp tests that heartbeats update timestamp
func TestExternalToolRegistry_HeartbeatUpdatesTimestamp(t *testing.T) {
	registry := agentictools.NewExternalToolRegistry()

	// Register tool
	reg := agentictools.ExternalToolRegistration{
		Name:        "file_read",
		Description: "Read a file",
		Provider:    "fs-provider",
		Parameters: map[string]interface{}{
			"type": "object",
		},
		Timestamp: time.Now(),
	}
	err := registry.RegisterExternalTool(reg)
	if err != nil {
		t.Fatalf("RegisterExternalTool() failed: %v", err)
	}

	// Record first heartbeat
	firstTime := time.Now()
	heartbeat1 := agentictools.ToolHeartbeat{
		Provider:  "fs-provider",
		Tools:     []string{"file_read"},
		Timestamp: firstTime,
	}
	registry.RecordHeartbeat(heartbeat1)

	// Small delay
	time.Sleep(10 * time.Millisecond)

	// Record second heartbeat
	secondTime := time.Now()
	heartbeat2 := agentictools.ToolHeartbeat{
		Provider:  "fs-provider",
		Tools:     []string{"file_read"},
		Timestamp: secondTime,
	}
	registry.RecordHeartbeat(heartbeat2)

	// Second timestamp should be more recent
	if !secondTime.After(firstTime) {
		t.Error("Second heartbeat timestamp should be after first")
	}

	// Provider should be healthy with recent heartbeat
	if !registry.IsProviderHealthy("fs-provider", 30*time.Second) {
		t.Error("IsProviderHealthy() should return true with recent heartbeat")
	}
}

// TestExternalToolRegistry_AvailabilityStateTransitions tests tool availability state changes
func TestExternalToolRegistry_AvailabilityStateTransitions(t *testing.T) {
	registry := agentictools.NewExternalToolRegistry()

	// Register tool
	reg := agentictools.ExternalToolRegistration{
		Name:        "file_read",
		Description: "Read a file",
		Provider:    "fs-provider",
		Parameters: map[string]interface{}{
			"type": "object",
		},
		Timestamp: time.Now(),
	}
	err := registry.RegisterExternalTool(reg)
	if err != nil {
		t.Fatalf("RegisterExternalTool() failed: %v", err)
	}

	// Record heartbeat - should make available
	heartbeat := agentictools.ToolHeartbeat{
		Provider:  "fs-provider",
		Tools:     []string{"file_read"},
		Timestamp: time.Now(),
	}
	registry.RecordHeartbeat(heartbeat)

	// Tool should be available
	tools := registry.ListExternalTools()
	available := false
	for _, tool := range tools {
		if tool.Name == "file_read" && tool.Provider == "fs-provider" {
			available = tool.Available
			break
		}
	}
	if !available {
		t.Error("Tool should be available after heartbeat")
	}

	// Mark provider unavailable
	registry.MarkProviderUnavailable("fs-provider")

	// Tool should now be unavailable
	tools = registry.ListExternalTools()
	for _, tool := range tools {
		if tool.Name == "file_read" && tool.Provider == "fs-provider" {
			if tool.Available {
				t.Error("Tool should be unavailable after MarkProviderUnavailable()")
			}
			break
		}
	}

	// Record new heartbeat - should restore availability
	heartbeat2 := agentictools.ToolHeartbeat{
		Provider:  "fs-provider",
		Tools:     []string{"file_read"},
		Timestamp: time.Now(),
	}
	registry.RecordHeartbeat(heartbeat2)

	// Tool should be available again
	tools = registry.ListExternalTools()
	available = false
	for _, tool := range tools {
		if tool.Name == "file_read" && tool.Provider == "fs-provider" {
			available = tool.Available
			break
		}
	}
	if !available {
		t.Error("Tool should be available again after new heartbeat")
	}
}
